import { 菩薩坐身, 前臂 } from './pusa.js';
import { 堅實心合掌 } from '../bujian/hezhang.js';
import { 腕釧 } from '../bujian/index.js';
export const 金剛業 = (bi) => 菩薩坐身(bi, {
    髮先: true,
    冠髻先: true,
    臂(bi, 筆) {
        const { M, C, Qk, S, 骨, 細, 陰, 陽 } = 筆;
        // 舉臂：肩峰而上，肘揚於頰際之外（杆自肩發，一氣上翻）
        骨(() => {
            陽(() => {
                M(-13.4, 28.6);
                C(-15.0, 26.2, -15.4, 23.2, -14.8, 20.9);
                S();
                M(-10.9, 32.4);
                C(-12.0, 29.2, -12.4, 25.8, -12.2, 22.8);
                S();
            });
            陰(() => {
                M(13.4, 28.6);
                C(15.0, 26.2, 15.4, 23.2, 14.8, 20.9);
                S();
                M(10.9, 32.4);
                C(12.0, 29.2, 12.4, 25.8, 12.2, 22.8);
                S();
            });
        });
        // 前臂上合：至頂上之腕（蔽法斷髮縷冠繒頭光於臂後；腕高舉，冠髻乃現於兩腕之間）
        骨(() => 陽(() => 前臂(bi, 筆, [-14.6, 21.1], [-1.9, 0.9], { 寬根: 2.4, 寬梢: 1.7, 弓: 0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [14.6, 21.1], [1.9, 0.9], { 寬根: 2.4, 寬梢: 1.7, 弓: -0.4, 肘帽: true })));
        // 合掌於頂上（堅實心：兩掌相貼十指齊）——高懸冠上
        堅實心合掌(bi, 0, -4.6, 0.8);
        // 嚴：舉臂之釧隨臂勢
        細(() => {
            for (const d of [-1, 1]) {
                M(d * 12.3, 24.6);
                Qk(d * 13.6, 25.4, d * 14.8, 24.6);
                S();
                M(d * 12.5, 23.6);
                Qk(d * 13.8, 24.4, d * 15.0, 23.6);
                S();
                bi.dot(d * 13.7, 24.5, 0.2);
            }
            腕釧(bi, [[-3.9, 2.4, -2.9, 3.1, -1.9, 3.3], [-3.5, 1.5, -2.5, 2.2, -1.5, 2.4]], [-2.7, 2.7]);
            腕釧(bi, [[3.9, 2.4, 2.9, 3.1, 1.9, 3.3], [3.5, 1.5, 2.5, 2.2, 1.5, 2.4]], [2.7, 2.7]);
        });
    },
});
